#!/bin/bash\n\n# FastHomeCash Spam Protection & Google Services Setup Script\n\necho \"=== FastHomeCash Spam Protection Setup ===\"\necho \"\"\n\n# Check if .env file exists\nif [ ! -f .env ]; then\n    echo \"❌ .env file not found. Please copy .env.example to .env first.\"\n    exit 1\nfi\n\necho \"✅ .env file found\"\n\n# Run database migrations\necho \"📦 Running database migrations...\"\nphp artisan migrate --force\n\nif [ $? -eq 0 ]; then\n    echo \"✅ Database migrations completed successfully\"\nelse\n    echo \"❌ Database migrations failed\"\n    exit 1\nfi\n\n# Clear and cache config\necho \"🔄 Clearing and caching configuration...\"\nphp artisan config:clear\nphp artisan config:cache\nphp artisan route:clear\nphp artisan route:cache\n\necho \"✅ Configuration cached\"\n\n# Install NPM dependencies and build assets\necho \"📦 Installing NPM dependencies...\"\nnpm install\n\nif [ $? -eq 0 ]; then\n    echo \"✅ NPM dependencies installed\"\nelse\n    echo \"❌ NPM installation failed\"\n    exit 1\nfi\n\necho \"🔨 Building frontend assets...\"\nnpm run build\n\nif [ $? -eq 0 ]; then\n    echo \"✅ Frontend assets built successfully\"\nelse\n    echo \"❌ Frontend build failed\"\n    exit 1\nfi\n\n# Check for Google API keys\necho \"\"\necho \"=== Configuration Check ===\"\n\n# Check reCAPTCHA configuration\nif grep -q \"GOOGLE_RECAPTCHA_SITE_KEY=\" .env && ! grep -q \"GOOGLE_RECAPTCHA_SITE_KEY=$\" .env; then\n    echo \"✅ Google reCAPTCHA Site Key configured\"\nelse\n    echo \"⚠️  Google reCAPTCHA Site Key not configured\"\n    echo \"   Get your keys from: https://www.google.com/recaptcha/admin\"\nfi\n\nif grep -q \"GOOGLE_RECAPTCHA_SECRET_KEY=\" .env && ! grep -q \"GOOGLE_RECAPTCHA_SECRET_KEY=$\" .env; then\n    echo \"✅ Google reCAPTCHA Secret Key configured\"\nelse\n    echo \"⚠️  Google reCAPTCHA Secret Key not configured\"\nfi\n\n# Check Google Places API configuration\nif grep -q \"GOOGLE_PLACES_API_KEY=\" .env && ! grep -q \"GOOGLE_PLACES_API_KEY=$\" .env; then\n    echo \"✅ Google Places API Key configured\"\nelse\n    echo \"⚠️  Google Places API Key not configured\"\n    echo \"   Get your key from: https://console.cloud.google.com/\"\n    echo \"   Enable: Places API and Maps JavaScript API\"\nfi\n\necho \"\"\necho \"=== Setup Complete ===\"\necho \"\"\necho \"📋 Next steps:\"\necho \"1. Configure Google API keys in your .env file if not already done\"\necho \"2. Test the forms on your website\"\necho \"3. Monitor spam logs in the admin panel\"\necho \"4. Review the SPAM_PROTECTION_README.md for detailed documentation\"\necho \"\"\necho \"🎉 Spam protection and Google services are now active!\"\n